// VERIFY SIGNATURE — rejette les requêtes sans le header X-Pessobot-Signature
// ⚠️ n8n Cloud Starter/Pro : secret hardcodé (pas de $env disponible).
const expected = '607dd413213a97fe2a54f9ebdab7341596d603640bb093ae';
const webhook = $('Webhook PessoBot').first().json;
const received = (webhook.headers && (webhook.headers['x-pessobot-signature'] || webhook.headers['X-Pessobot-Signature'])) || '';
if (expected && received !== expected) {
  throw new Error('Unauthorized: invalid or missing X-Pessobot-Signature header');
}
return [{ json: webhook }];

// Build 429 message : reformule la raison technique en message utilisateur chaleureux.
const r = $input.first().json;
const retry = Number(r.retry_after_seconds) || 10;
const reason = r.reason || 'Pause technique';
let userMsg;
if (reason.startsWith('Rafale')) {
  userMsg = `Houla, ${retry} s de pause — je te réponds juste après 🙏`;
} else if (reason.startsWith('Trop')) {
  userMsg = `On fait beaucoup d'échanges depuis ton IP (limite 30 / 10 min). Reviens dans ~${Math.ceil(retry / 60)} min, je garderai le fil de notre conversation.`;
} else {
  userMsg = `Petit temps de pause côté serveur, ré-essaie dans ${retry} s.`;
}
return [{ json: { response: userMsg, rate_limited: true, retry_after_seconds: retry } }];

// ────────────────────────────────────────────────────────────────────────────
// BUILD SYSTEM PROMPT (v3.2 — snapshot menu serveur + tools)
// Le nœud « Menu snapshot » agrège v_pessobot_menu en JSON ; injection chaque requête.
// ────────────────────────────────────────────────────────────────────────────

// 1. Webhook
const webhook = $('Webhook PessoBot').first().json;
const userMsg = (webhook.body && webhook.body.message) || '';
const sessionId = (webhook.body && webhook.body.sessionid) || 'session-inconnue';
const userId = (webhook.body && webhook.body.userId) || null;

// 2. Profile snapshot + bar (requête combinée — optim v3.1)
let snap = {};
let bar = { address: {}, hours: [], contact: {}, subscription_info: {} };
try {
  const rows = $('Get Profile + Bar').all();
  if (rows[0] && rows[0].json) {
    snap = rows[0].json.profile || {};
    if (rows[0].json.bar) bar = rows[0].json.bar;
  }
} catch (e) {}

// 2bis. Catalogue officiel (nœud Postgres « Menu snapshot»)
let menuCompact = '[]';
let menuCount = 0;
try {
  const mrow = $('Menu snapshot').first();
  const raw = mrow && mrow.json && mrow.json.menu_compact;
  if (raw != null) {
    if (Array.isArray(raw)) {
      menuCount = raw.length;
      menuCompact = JSON.stringify(raw);
    } else if (typeof raw === 'string') {
      const parsed = JSON.parse(raw);
      menuCount = Array.isArray(parsed) ? parsed.length : 0;
      menuCompact = JSON.stringify(parsed);
    } else {
      menuCompact = JSON.stringify(raw);
      menuCount = Array.isArray(raw) ? raw.length : 1;
    }
  }
} catch (e) {}

// Connexion = JWT côté app : dès que userId est envoyé, l'utilisateur n'est plus visiteur.
// (L'ancienne règle exigeait snap.first_name — faux négatif si prénom vide en BDD.)
const firstName =
  (snap.first_name && String(snap.first_name).trim()) ||
  (webhook.body && webhook.body.first_name && String(webhook.body.first_name).trim()) ||
  'Membre';
const isConnected = Boolean(userId);
const plan = (snap.plan || (webhook.body && webhook.body.subscription_tier) || 'free').toLowerCase();
const isOraPlus = ['ora_plus', 'starter', 'premium', 'vip'].includes(plan);
const totalOrders = snap.total_orders || 0;
const isRegular = isConnected && totalOrders >= 3;

let clientStatus = 'VISITOR';
if (isConnected) clientStatus = isOraPlus ? 'VIP_MEMBER' : 'FREE_MEMBER';

// Signaux perso (compact JSON pour le prompt)
const personalSignals = {};
if (snap.favorite_product) personalSignals.favorite = snap.favorite_product;
if (snap.upcoming_event) personalSignals.upcoming_event = snap.upcoming_event;
if (snap.upcoming_bilan) personalSignals.upcoming_bilan = snap.upcoming_bilan;
if (totalOrders) personalSignals.total_orders = totalOrders;

// 3. Bar settings (déjà chargés en étape 2 via la requête combinée)
const addressLine = (bar.address && bar.address.full) || '(non renseignée)';
const hoursCompact = Array.isArray(bar.hours)
  ? bar.hours.map(h => `${h.label} ${h.value}`).join(' | ')
  : '(non renseignées)';
const contact = bar.contact || {};
const contactLine = [contact.email, contact.phone, contact.instagram].filter(Boolean).join(' · ') || '(non renseigné)';

// Óra+ compact
const oraPlus = (bar.subscription_info && bar.subscription_info.ora_plus) || null;
const oraPlusJson = oraPlus ? JSON.stringify({
  name: oraPlus.name,
  tagline: oraPlus.tagline,
  price: oraPlus.price,
  period: oraPlus.period,
  highlight: oraPlus.highlight,
  benefits: oraPlus.benefits,
  cta_url: oraPlus.cta_url,
}) : 'null';

// 4. Closing tactique (adapté au statut + historique)
let closing;
if (clientStatus === 'VISITOR') {
  closing = 'Ferme par : "Crée ton compte gratuit pour commander". Jamais de demande de paiement ici.';
} else if (clientStatus === 'FREE_MEMBER' && isRegular && oraPlus) {
  closing = `${firstName} est un habitué (${totalOrders} commandes). Si le contexte s'y prête, glisse UNE FOIS le pitch Óra+ en citant 1 ou 2 bénéfices réels du JSON ora_plus ci-dessous. Utilise un lien markdown [S'abonner à ${oraPlus.name}](${oraPlus.cta_url}). Ne force jamais.`;
} else if (clientStatus === 'FREE_MEMBER' && oraPlus) {
  closing = `Conseille simplement. Si le produit est éligible Óra+ et que c'est naturel, glisse : "Avec ${oraPlus.name} ce serait moins cher (${oraPlus.highlight})". Une seule fois, sans insister.`;
} else if (clientStatus === 'VIP_MEMBER') {
  closing = `${firstName} est déjà abonné(e) ${oraPlus ? oraPlus.name : 'Óra+'}. Confirme simplement le plaisir, rappelle les avantages exclusifs (bilan prioritaire, places événements). Pas d'upsell.`;
} else {
  closing = 'Conseille simplement, pas d\'upsell.';
}

// 5. Persona v3 (compacte, ~400 tokens vs ~900 en v2.1)
const who = isConnected ? firstName : 'un visiteur anonyme';
const personalJson = Object.keys(personalSignals).length ? JSON.stringify(personalSignals) : 'null';

const systemPrompt = `Tu es PessoBot, assistant du bar PessÓra (Martinique).

RÈGLES ABSOLUES :
1. JAMAIS d'info bar/menu/abonnement inventée. Produits / prix / kcal / pitch / ingrédients : UNIQUEMENT le JSON CATALOGUE_OFFICIEL ci-dessous (snapshot BDD) OU les champs renvoyés par get_menu dans ce même tour.
2. INTERDIT : nommer une boisson absente du JSON, un prix ou des kcal non listés, ou des noms génériques type « smoothie immunité », Détox, Focus, pré-workout comme nom de produit.
3. Reprends chaque name exactement comme dans le JSON (ex. DETOX MY BODY). Ne crée pas de variantes orthographiques.
4. Si CATALOGUE_OFFICIEL est vide ([]) : ne fabrique pas de carte. Dis que la carte n'est pas disponible et renvoie vers [Menu](/menu).
5. Si tu ne sais pas (hors carte) : dis-le.
6. Tu parles à ${who} (${clientStatus}${isConnected ? `, plan=${plan}` : ''}). Reste court, chaleureux, précis.
7. Pas de titres markdown lourds. Liens en [libellé](URL).
8. Signaux perso avec tact, jamais listés brut.

MÉTHODE :
- Le snapshot menu est déjà fourni : réponds depuis ce JSON pour toute question carte, boisson, tarif ou conseil goût.
- get_menu(category?) — optionnel pour filtrer wellness | energie | shakes | coffee si la question porte sur une seule gamme.
- get_upcoming_events(limit?) — obligatoire pour événements, ateliers, dates.

CATALOGUE_OFFICIEL (${menuCount} produit(s)) :
${menuCompact}

TOOLS :
- get_menu(category?) — filtre par gamme (le snapshot ci-dessus reste la base).
- get_upcoming_events(limit?) — événements publics à venir.

INFOS BAR (pré-chargées) :
- Adresse : ${addressLine}
- Horaires : ${hoursCompact}
- Contact : ${contactLine}

PROFIL UTILISATEUR (JSON compact) : ${personalJson}
ABONNEMENT ÓRA+ (JSON, à citer tel quel) : ${oraPlusJson}

CLOSING :
${closing}`;

return [{ json: { systemPrompt, userMessage: userMsg, sessionId } }];

// Nettoyage léger du markdown retourné par l'agent :
// - on retire les titres markdown (# / ##) qui n'ont pas leur place dans une bulle de chat
// - on convertit les puces '- ' / '• ' en '👉 ' (cohérent avec la persona)
// - on supprime les séparateurs '---' / '***' (bruit visuel)
// On LAISSE passer **bold** et *italic* : le front les rend en <strong>/<em>.
let rawText = $input.first().json.output || '';
let cleanText = rawText
  .replace(/^[#]+\s+/gm, '')
  .replace(/^[-\u2022]\s+/gm, '👉 ')
  .replace(/^\s*-{3,}\s*$/gm, '')
  .trim();
return [{ json: { response: cleanText } }];
